    12→  final AddTrustedContactUseCase _addContact;
    13→  final RemoveTrustedContactUseCase _removeContact;
    14→  final UpdateTrustedContactUseCase _updateContact;
    15→  final GetTrustedContactsUseCase _getContacts;
    16→  final StateNotifierProviderRef _ref;
    17→
    18→  TrustedContactsNotifier({
    19→    required AddTrustedContactUseCase addContact,
    20→    required RemoveTrustedContactUseCase removeContact,
    21→    required UpdateTrustedContactUseCase updateContact,
    22→    required GetTrustedContactsUseCase getContacts,
    23→    required StateNotifierProviderRef ref,
    24→  })  : _addContact = addContact,
    25→        _removeContact = removeContact,
    26→        _updateContact = updateContact,
    27→        _getContacts = getContacts,
    28→        _ref = ref,
    29→        super(const TrustedContactsState());
    30→
    31→  /// Load all trusted contacts
    32→  Future<void> loadContacts() async {
    33→    if (state.isLoading) return;
    34→
    35→    state = state.copyWith(isLoading: true, error: null);
    36→    try {
    37→      final contacts = await _getContacts();
    38→      state = state.copyWith(
    39→        isLoading: false,
    40→        contacts: contacts,
    41→        error: null,
    42→      );
    43→    } catch (e) {
    44→      state = state.copyWith(
    45→        isLoading: false,
    46→        error: e.toString(),
    47→      );
    48→    }
    49→  }
    50→
    51→  /// Add a new trusted contact
    52→  Future<void> addContact(TrustedContact contact) async {
    53→    if (state.isAdding) return;
    54→
    55→    state = state.copyWith(isAdding: true, error: null);
    56→    try {
    57→      final newContact = await _addContact(contact);
    58→      final updatedContacts = [...state.contacts, newContact];
    59→      state = state.copyWith(
    60→        isAdding: false,
    61→        contacts: updatedContacts,
    62→        selectedContact: newContact,
    63→        error: null,
    64→      );
    65→    } catch (e) {
    66→      state = state.copyWith(
    67→        isAdding: false,
    68→        error: e.toString(),
    69→      );
    70→    }
    71→  }
    72→
    73→  /// Update an existing trusted contact
    74→  Future<void> updateContact(TrustedContact contact) async {
    75→    if (state.isUpdating) return;
    76→
    77→    state = state.copyWith(isUpdating: true, error: null);
    78→    try {
    79→      final updatedContact = await _updateContact(contact);
    80→      final updatedContacts = state.contacts.map((c) {
    81→        return c.id == contact.id ? updatedContact : c;
    82→      }).toList();
    83→      state = state.copyWith(
    84→        isUpdating: false,
    85→        contacts: updatedContacts,
    86→        selectedContact: updatedContact,
    87→        error: null,
    88→      );
    89→    } catch (e) {
    90→      state = state.copyWith(
    91→        isUpdating: false,
    92→        error: e.toString(),
    93→      );
    94→    }
    95→  }
    96→
    97→  /// Remove a trusted contact
    98→  Future<void> removeContact(String contactId) async {
    99→    if (state.isRemoving) return;
   100→
   101→    state = state.copyWith(isRemoving: true, error: null);
   102→    try {
   103→      await _removeContact(contactId);
   104→      final updatedContacts = state.contacts
   105→          .where((contact) => contact.id != contactId)
   106→          .toList();
   107→      state = state.copyWith(
   108→        isRemoving: false,
   109→        contacts: updatedContacts,
   110→        selectedContact: state.selectedContact?.id == contactId
   111→            ? null
   112→            : state.selectedContact,
   113→        error: null,
   114→      );
   115→    } catch (e) {
   116→      state = state.copyWith(
   117→        isRemoving: false,
   118→        error: e.toString(),
   119→      );
   120→    }
   121→  }
   122→
   123→  /// Select a contact for viewing/editing
   124→  void selectContact(TrustedContact? contact) {
   125→    state = state.copyWith(selectedContact: contact);
   126→  }
   127→
   128→  /// Clear the selected contact
   129→  void clearSelection() {
   130→    state = state.copyWith(clearSelected: true);
   131→  }
   132→
   133→  /// Clear any error message
   134→  void clearError() {
   135→    state = state.copyWith(error: null);
   136→  }
   137→
   138→  /// Update location sharing for a contact
   139→  Future<void> updateLocationSharing(
   140→    String contactId,
   141→    bool enabled,
   142→  ) async {
   143→    final contact = state.contacts.firstWhere(
   144→      (c) => c.id == contactId,
   145→      orElse: () => throw Exception('Contact not found'),
   146→    );
   147→
   148→    final updatedContact = contact.copyWith(
   149→      locationSharingEnabled: enabled,
   150→    );
   151→
   152→    await updateContact(updatedContact);
   153→  }
   154→
   155→  /// Update emergency alerts for a contact
